#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

const root = process.cwd();
const unitKey = process.argv[2] || 'alphabet';
const runtimeDir = path.join(root, 'src', 'units', unitKey, 'runtime');
const outputPath = path.join(runtimeDir, 'runtime.bundle.js');

const manifest = [
  'bootstrap.js',
  'steps.js',
  'progress.js',
  'grid.js',
  'media.js',
  'speak.js',
  'write.js',
  'ui-bindings.js',
];

function fail(message) {
  console.error(message);
  process.exit(1);
}

if (!fs.existsSync(runtimeDir)) {
  fail(`Runtime fragment folder not found: ${runtimeDir}`);
}

const parts = [
  '/*',
  `  Generated runtime bundle for ${unitKey}.`,
  '  Do not edit this file directly; edit runtime/*.js and rerun this tool.',
  '*/',
  '',
];

for (const file of manifest) {
  const filePath = path.join(runtimeDir, file);
  if (!fs.existsSync(filePath)) {
    fail(`Missing runtime fragment: ${path.relative(root, filePath)}`);
  }

  parts.push(`\n/* ===== ${file} ===== */\n`);
  parts.push(fs.readFileSync(filePath, 'utf8'));
}

fs.writeFileSync(outputPath, parts.join('\n'), 'utf8');
console.log(`Built runtime bundle: ${path.relative(root, outputPath)}`);
